import{_ as e,c as i,o as a,aj as r}from"./chunks/framework.HLg5PcC2.js";const c=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function o(s,t,l,d,p,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to “Getting Started”">​</a></h1><p>Welcome to Primitive! This guide will help you understand the platform and build your first app.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to “Quick Start”">​</a></h2><p>New to Primitive? Start here:</p><ol><li><p><strong><a href="./getting-started/template-app.html">Starting with the Template App</a></strong> — Create a new project, configure authentication, and run your first app in minutes.</p></li><li><p><strong><a href="./getting-started/local-first-model.html">The Local-First Model</a></strong> — Understand how Primitive apps work differently from traditional web apps.</p></li><li><p><strong><a href="./getting-started/understanding-documents.html">Understanding Documents</a></strong> — Learn about documents, sharing, and choosing the right pattern for your app.</p></li><li><p><strong><a href="./getting-started/working-with-data.html">Working with Data</a></strong> — Define data models and perform create, read, update, and delete operations.</p></li></ol><h2 id="additional-topics" tabindex="-1">Additional Topics <a class="header-anchor" href="#additional-topics" aria-label="Permalink to “Additional Topics”">​</a></h2><ul><li><p><strong><a href="./getting-started/other-services.html">Other Services</a></strong> — Blob storage, AI integration, third-party APIs, analytics, and waitlist features.</p></li><li><p><strong><a href="./getting-started/good-and-bad-apps.html">Is Primitive Right for You?</a></strong> — Understand where Primitive shines and where it might not be the best fit.</p></li></ul><h2 id="what-is-primitive" tabindex="-1">What is Primitive? <a class="header-anchor" href="#what-is-primitive" aria-label="Permalink to “What is Primitive?”">​</a></h2><p>Primitive is a platform for building <strong>local-first web applications</strong>. Instead of building APIs and managing servers, you write client-side code that works with a local database. Primitive handles:</p><ul><li><strong>Data sync</strong> — Changes automatically sync between devices and users</li><li><strong>Authentication</strong> — Google OAuth built in</li><li><strong>Real-time collaboration</strong> — Multiple users can edit shared data simultaneously</li><li><strong>Offline support</strong> — Apps work without an internet connection</li><li><strong>Additional services</strong> — Blob storage, AI, third-party API proxy, analytics</li></ul><p>You focus on building your product. Primitive handles the infrastructure.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to “Prerequisites”">​</a></h2><p>Before diving in, you should be comfortable with:</p><ul><li><strong>JavaScript/TypeScript</strong> — All code runs in the browser</li><li><strong>Vue 3</strong> — The template uses Vue with the Composition API</li><li><strong>Modern web development</strong> — npm/pnpm, Vite, etc.</li></ul><p>No backend experience required—that&#39;s the point!</p>',15)])])}const u=e(n,[["render",o]]);export{c as __pageData,u as default};
